#!/usr/bin/env python

import json
import os.path as osp
from mintrans import GoogleTranslator

SOURCE_LANG = "en"
WEBEXT_LOCALES = [
    "de",
    "es",
    "fr",
    "it",
    "ja",
    "ko",
    "pl",
    "pt_BR",
    "ru",
    "tr",
    "zh_CN",
    "zh_TW",
]

def get_messages(data):
    items = [
        (key, data[key]["message"])
        for key in data.keys()
        if not key.startswith("__WET")
    ]
    return dict(items)

def remove_stops_newlines(text):
    return text.replace("\n", " ### ").replace(". ", " @@@ ")

def replace_stops_newlines(text):
    return text.replace(" ### ", "\n").replace(" @@@ ", ". ")

def main():
    google_translator = GoogleTranslator()

    src_root = osp.abspath(osp.join(osp.dirname(__file__), "..", "extension"))
    with open(osp.join(src_root, "_locales/en/messages.json")) as fp:
        source_strings_data = json.load(fp)

    source_messages = get_messages(source_strings_data)

    for lang in ["es"]:
        print(f"Translating {lang}.")
        with open(osp.join(src_root, f"_locales/{lang}/messages.json")) as fp:
            lang_data = json.load(fp)

        source_keys = tuple(source_messages.keys())
        dest_messages = get_messages(lang_data)
        dest_messages_ids = tuple(dest_messages.keys())
        dest_messages_values = [remove_stops_newlines(v) for v in dest_messages.values()]

        gt = google_translator.translate("\n".join(dest_messages_values), lang, "en-US")
